fn main(c: Console) -> Unit {
  let cf = array(3)
  aset(cf, 0, 100.0)
  aset(cf, 1, 100.0)
  aset(cf, 2, 100.0)
  let r: Float = 0.05
  var pv: Float = 0.0
  var i: Int = 0
  while i < alen(cf) {
    let t: Float = to_float(i + 1)
    pv = pv + aget(cf, i) / pow(1.0 + r, t)
    i = i + 1
  }
  c.print_int(round(pv * 100.0))
}

type Cf = { amt: Float, t: Float }

fn pv1(z: Cf, r: Float) -> Float {
  return z.amt / pow(1.0 + r, z.t)
}

fn main(c: Console) -> Unit {
  let x = Cf { amt: 100.0, t: 2.0 }
  c.print_int(round(pv1(x, 0.05) * 100.0))
}

fn norm_cdf(x: Float) -> Float {
  if x < 0.0 {
    return 1.0 - norm_cdf(-x)
  }
  let k: Float = 1.0 / (1.0 + 0.2316419 * x)
  let poly: Float = k * (0.319381530 + k * (-0.356563782 + k * (1.781477937 + k * (-1.821255978 + k * 1.330274429))))
  let pdf: Float = (1.0 / sqrt(2.0 * 3.14159265358979)) * exp(-(x * x) / 2.0)
  return 1.0 - pdf * poly
}

fn bs_call(s: Float, k: Float, r: Float, t: Float, vol: Float) -> Float {
  let d1: Float = (ln(s / k) + (r + vol * vol / 2.0) * t) / (vol * sqrt(t))
  let d2: Float = d1 - vol * sqrt(t)
  return s * norm_cdf(d1) - k * exp(-r * t) * norm_cdf(d2)
}

fn main(c: Console) -> Unit {
  let price: Float = bs_call(100.0, 100.0, 0.05, 1.0, 0.2)
  c.print_int(round(price * 10000.0))
}

type Opt = { s: Float, k: Float, r: Float, t: Float, vol: Float }

fn norm_cdf(x: Float) -> Float {
  if x < 0.0 {
    return 1.0 - norm_cdf(-x)
  }
  let k: Float = 1.0 / (1.0 + 0.2316419 * x)
  let poly: Float = k * (0.319381530 + k * (-0.356563782 + k * (1.781477937 + k * (-1.821255978 + k * 1.330274429))))
  let pdf: Float = (1.0 / sqrt(2.0 * 3.14159265358979)) * exp(-(x * x) / 2.0)
  return 1.0 - pdf * poly
}

fn bs_call_rec(o: Opt) -> Float {
  let d1: Float = (ln(o.s / o.k) + (o.r + o.vol * o.vol / 2.0) * o.t) / (o.vol * sqrt(o.t))
  let d2: Float = d1 - o.vol * sqrt(o.t)
  return o.s * norm_cdf(d1) - o.k * exp(-o.r * o.t) * norm_cdf(d2)
}

fn main(c: Console) -> Unit {
  let opt = Opt { s: 100.0, k: 100.0, r: 0.05, t: 1.0, vol: 0.2 }
  let price: Float = bs_call_rec(opt)
  c.print_int(round(price * 10000.0))
}
